  };

  const checkWinCondition = (currentBoard: CellData[][]) => {
    const isFull = currentBoard.every(row => row.every(cell => cell.value !== null));
    const isCorrect = currentBoard.every(row => row.every(cell => !cell.isError));

    if (isFull && isCorrect) {
      setStatus('won');
    }
  };

  // --- Rendering Helpers ---

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  // Derived state for highlighting
  const activeValue = selectedPos ? board[selectedPos.r][selectedPos.c].value : null;

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 flex flex-col items-center py-4 sm:py-8 font-inter transition-colors">

      {/* --- HEADER --- */}
      <header className="w-full max-w-md px-4 flex items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold tracking-tight bg-gradient-to-r from-indigo-500 to-purple-600 bg-clip-text text-transparent">
            Zenith Sudoku
          </h1>
          <div className="flex items-center text-sm text-slate-500 dark:text-slate-400 gap-3">
             <span className="font-mono">{formatTime(timer)}</span>
             <span>•</span>
             <span className={`${mistakes > 2 ? 'text-red-500' : ''}`}>Mistakes: {mistakes}/3</span>
          </div>
        </div>

        <div className="flex gap-2">
           <button 
             onClick={() => setStatus(status === 'paused' ? 'playing' : 'paused')} 
             className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors"
           >
             {status === 'paused' ? <Play size={24} /> : <Pause size={24} />}
           </button>
           <button 
             onClick={() => setShowSettings(!showSettings)} 
             className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors"
           >
             <Settings size={24} />
           </button>
        </div>
      </header>

      {/* --- SETTINGS DROPDOWN --- */}
      {showSettings && (
        <div className="w-full max-w-md px-4 mb-6 animate-in slide-in-from-top-2 fade-in">
           <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-lg border border-slate-200 dark:border-slate-700">
              <p className="text-xs font-bold uppercase text-slate-400 mb-3">Difficulty</p>
              <div className="flex gap-2">
                 {(['Easy', 'Medium', 'Hard'] as Difficulty[]).map(d => (
                   <button
                     key={d}
                     onClick={() => { startNewGame(d); setShowSettings(false); }}
                     className={`flex-1 py-2 text-sm rounded-lg font-medium transition-colors ${difficulty === d ? 'bg-indigo-600 text-white' : 'bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600'}`}
                   >
                     {d}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}

      {/* --- GAME BOARD CONTAINER --- */}
      <main className="relative w-full max-w-md px-2 flex-grow flex flex-col items-center">

        {/* Loading Overlay */}
        {status === 'loading' && (
           <div className="absolute inset-0 z-50 flex items-center justify-center bg-slate-50/80 dark:bg-slate-900/80 backdrop-blur-sm">
              <Loader2 className="w-10 h-10 animate-spin text-indigo-600" />
           </div>
        )}

        {/* Win Overlay */}
        {status === 'won' && (
          <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-indigo-900/90 backdrop-blur-md rounded-xl text-white animate-in zoom-in-95 duration-300">
             <Trophy className="w-16 h-16 text-yellow-400 mb-4 drop-shadow-lg" />
             <h2 className="text-3xl font-bold mb-2">Solved!</h2>
             <p className="text-indigo-200 mb-6">{difficulty} • {formatTime(timer)}</p>
             <button 
               onClick={() => startNewGame(difficulty)}
               className="px-8 py-3 bg-white text-indigo-900 font-bold rounded-full shadow-lg hover:scale-105 transition-transform"
             >
               New Game
             </button>
          </div>
        )}

        {/* AI Hint Message Bubble */}
        {hintMessage && (
           <div className="mb-4 w-full bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-700/50 p-3 rounded-lg flex gap-3 animate-in fade-in slide-in-from-bottom-2">
              <Lightbulb className="w-5 h-5 text-amber-500 flex-shrink-0 mt-0.5" />
              <p className="text-sm text-slate-700 dark:text-slate-300 leading-relaxed">{hintMessage}</p>
           </div>
        )}

        {/* The Grid */}
        <div className="w-full aspect-square bg-slate-800 p-1 sm:p-2 rounded-lg shadow-2xl overflow-hidden select-none">
          <div className="w-full h-full grid grid-cols-9 gap-[1px] bg-slate-300 dark:bg-slate-700 border-2 border-slate-800 dark:border-slate-950">
            {board.map((row, rIndex) => 
               row.map((cell, cIndex) => {
                  // Determine block borders (every 3rd cell)
                  const borderR = (cIndex + 1) % 3 === 0 && cIndex !== 8 ? 'border-r-2 border-slate-500 dark:border-slate-900' : '';
                  const borderB = (rIndex + 1) % 3 === 0 && rIndex !== 8 ? 'border-b-2 border-slate-500 dark:border-slate-900' : '';

                  // Selection logic
                  const isSelected = selectedPos?.r === rIndex && selectedPos?.c === cIndex;
                  const isRelated = selectedPos ? (selectedPos.r === rIndex || selectedPos.c === cIndex) : false;
                  // Is same value (highlight all 5s if 5 is selected)
                  const isActive = activeValue !== null && cell.value === activeValue;

                  return (
                    <div 
                      key={`${rIndex}-${cIndex}`} 
                      className={`relative w-full h-full ${borderR} ${borderB}`}
                    >
                      <SudokuCell
                        cell={cell}
                        isSelected={isSelected}
                        isRelated={isRelated}
                        isActive={isActive}
                        mode={inputMode}
                        onClick={() => handleCellClick(rIndex, cIndex)}
                        onInput={() => {}} // Controlled by global controls mostly, local canvas handles touch
                      />
                    </div>
                  );
               })
            )}
          </div>
        </div>

        {/* Controls */}
        <Controls 
          inputMode={inputMode}
          setInputMode={setInputMode}
          onNumberClick={handleNumberInput}
          onUndo={handleUndo}
          onErase={handleErase}
          onHint={handleHint}
          canUndo={history.length > 0}
          hintsRemaining={hints}
        />

      </main>

      {/* Footer */}
      <footer className="mt-8 text-xs text-slate-400">
         Zenith Sudoku • v1.0.0
      </footer>

    </div>
  );
};

