import React from 'react';

interface AbacusDisplayProps {
  value: number;
  className?: string;
  compact?: boolean; // For smaller displays like notes or keypad
}

// Extract Bead component to prevent re-creation on every render
const Bead = ({ x, y, active }: { x: number, y: number, active: boolean }) => {
  const beadActiveColor = "fill-indigo-600 dark:fill-indigo-400 stroke-indigo-700 dark:stroke-indigo-300 stroke-1";
  const beadInactiveColor = "fill-slate-200 dark:fill-slate-700 stroke-slate-300 dark:stroke-slate-600 stroke-1 opacity-60";

  return (
    <path 
      d={`M ${x - 12} ${y} L ${x} ${y - 5} L ${x + 12} ${y} L ${x} ${y + 5} Z`} 
      className={active ? beadActiveColor : beadInactiveColor}
    />
  );
};

const AbacusDisplay: React.FC<AbacusDisplayProps> = ({ value, className = "", compact = false }) => {
  const hasFive = value >= 5;
  const ones = value % 5;

  // Soroban Geometry
  // ViewBox 0 0 40 100
  // Beam at y=30

  // Colors
  const rodColor = "stroke-slate-300 dark:stroke-slate-600";
  const beamColor = "stroke-slate-800 dark:stroke-slate-200";

  return (
    <svg viewBox="0 0 40 100" className={`${className} select-none w-full h-full`}>
       {/* Rod */}
       <line x1="20" y1="5" x2="20" y2="95" strokeWidth="2" className={rodColor} strokeLinecap="round" />

       {/* Beam */}
       <line x1="2" y1="30" x2="38" y2="30" strokeWidth="3" className={beamColor} strokeLinecap="round" />

       {/* Heaven Bead (5) */}
       {/* Active (Down, touching beam): y=23. Inactive (Up): y=10 */}
       <Bead x={20} y={hasFive ? 23 : 10} active={hasFive} />

       {/* Earth Beads (1s) */}
       {[0, 1, 2, 3].map(i => {
          const isActive = i < ones;
          let y = 38 + i * 11;
          if (!isActive) {
             y += 20; // The gap
          }
          return <Bead key={i} x={20} y={y} active={isActive} />
       })}
    </svg>
  );
};

export default React.memo(AbacusDisplay);

import React, { useRef, useState, useEffect } from 'react';
import { CellData, Point, DisplayMode } from '../types';
import { Pencil } from 'lucide-react';
import AbacusDisplay from './AbacusDisplay';
import { recognizeDigit } from '../services/recognizer';

interface SudokuCellProps {
  cell: CellData;
  isSelected: boolean;
  isActive: boolean; // Same number selected elsewhere
  isRelated: boolean; // Same row/col/box
  mode: 'numpad' | 'note' | 'handwriting';
  displayMode: DisplayMode;
  onClick: () => void;
  onInput: (val: number, mode: 'value' | 'note') => void;
}

const SudokuCell: React.FC<SudokuCellProps> = ({
  cell,
  isSelected,
  isActive,
  isRelated,
  mode,
  displayMode,
  onClick,
  onInput
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const strokes = useRef<Point[][]>([]);
  const currentStroke = useRef<Point[]>([]);
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Clean up timeout on unmount
  useEffect(() => {
    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
    };
  }, []);

  // Styling logic
  const baseClasses = "relative flex items-center justify-center text-xl sm:text-2xl md:text-3xl cursor-pointer select-none transition-all duration-200 border-r border-b border-slate-300 dark:border-slate-700";

  let bgClass = "bg-white dark:bg-slate-800";
  if (cell.isError) bgClass = "bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400";
  else if (isSelected) bgClass = "bg-indigo-500 text-white shadow-lg scale-105 z-10 rounded-md";
  else if (isActive) bgClass = "bg-indigo-200 dark:bg-indigo-900/50 text-indigo-900 dark:text-indigo-100";
  else if (isRelated) bgClass = "bg-slate-100 dark:bg-slate-700/50";

  const textClass = cell.isFixed 
    ? (isSelected ? "font-bold" : "font-bold text-slate-900 dark:text-slate-100") 
    : (isSelected ? "font-medium" : "font-medium text-indigo-600 dark:text-indigo-400");

  // Handwriting Logic - Canvas setup
  useEffect(() => {
    if (!canvasRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.lineWidth = 3;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = isSelected ? '#ffffff' : '#4f46e5'; 
    }
  }, [cell.value, isSelected]);

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    if (mode !== 'handwriting' || cell.isFixed) return;

    if (!isSelected) onClick();

    setIsDrawing(true);
    const pos = getPos(e);
    currentStroke.current = [pos];

    if (timeoutRef.current) clearTimeout(timeoutRef.current);
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing || !canvasRef.current) return;
    e.preventDefault(); 

    const pos = getPos(e);
    currentStroke.current.push(pos);

    const ctx = canvasRef.current.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      const prev = currentStroke.current[currentStroke.current.length - 2];
      ctx.moveTo(prev.x, prev.y);
      ctx.lineTo(pos.x, pos.y);
      ctx.stroke();
    }
  };

  const endDrawing = () => {
    if (!isDrawing) return;
    setIsDrawing(false);
    strokes.current.push([...currentStroke.current]);

    timeoutRef.current = setTimeout(() => {
      processHandwriting();
    }, 600);
  };

  const processHandwriting = () => {
    if (strokes.current.length === 0) return;

    // Use the basic recognizer
    const digit = recognizeDigit(strokes.current);

    if (digit) {
       onInput(digit, 'value');
    }

    // Clear Canvas
    if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        ctx?.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
    strokes.current = [];
  };

  const getPos = (e: React.MouseEvent | React.TouchEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    return {
      x: clientX - rect.left,
      y: clientY - rect.top
    };
  };

  return (
    <div 
      className={`${baseClasses} ${bgClass}`}
      onClick={mode !== 'handwriting' ? onClick : undefined}
      style={{ aspectRatio: '1/1' }}
      onMouseDown={mode === 'handwriting' ? startDrawing : undefined}
      onMouseMove={mode === 'handwriting' ? draw : undefined}
      onMouseUp={mode === 'handwriting' ? endDrawing : undefined}
      onMouseLeave={mode === 'handwriting' ? endDrawing : undefined}
      onTouchStart={mode === 'handwriting' ? startDrawing : undefined}
      onTouchMove={mode === 'handwriting' ? draw : undefined}
      onTouchEnd={mode === 'handwriting' ? endDrawing : undefined}
    >
      {/* Main Value */}
      {cell.value && (
        displayMode === 'abacus' ? (
          <div className="w-full h-full p-1 sm:p-2">
            <AbacusDisplay value={cell.value} />
          </div>
        ) : (
          <span className={`${textClass} text-3xl`}>{cell.value}</span>
        )
      )}

      {/* Pencil Marks / Notes */}
      {!cell.value && cell.notes.length > 0 && (
        <div className="grid grid-cols-3 gap-0.5 p-0.5 w-full h-full pointer-events-none">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
            <div key={n} className="flex items-center justify-center text-[8px] sm:text-[10px] leading-none text-slate-500 dark:text-slate-400">
              {cell.notes.includes(n) ? n : ''}
            </div>
          ))}
        </div>
      )}

      {/* Handwriting Layer */}
      {mode === 'handwriting' && !cell.isFixed && (
        <canvas 
            ref={canvasRef}
            width={80} // Internal res
            height={80}
            className="absolute inset-0 w-full h-full touch-none"
        />
      )}

      {/* Handwriting Indicator */}
      {mode === 'handwriting' && !cell.value && isSelected && (
         <Pencil className="absolute bottom-1 right-1 w-3 h-3 text-indigo-400 opacity-50 pointer-events-none animate-pulse" />
      )}
    </div>
  );
};

