         </div>
       )}

      {/* Handwriting Instruction */}
      {inputMode === 'handwriting' && (
        <div className="h-32 flex items-center justify-center border-2 border-dashed border-slate-300 dark:border-slate-700 rounded-xl mx-2 bg-slate-50 dark:bg-slate-800/50">
          <div className="text-center text-slate-400 px-6">
            <PenLine size={32} className="mx-auto mb-2 opacity-50" />
