                        displayMode={displayMode}
                        onClick={() => handleCellClick(rIndex, cIndex)}
                        onInput={(val, mode) => handleNumberInput(val, mode)} // CORRECTED: Pass val and mode
                      />
                    </div>
                  );
               })
            )}
          </div>
        </div>

        {/* Controls */}
        <Controls 
          inputMode={inputMode}
          displayMode={displayMode}
          setInputMode={setInputMode}
          onNumberClick={(n) => handleNumberInput(n)}
          onUndo={handleUndo}
