import Controls from './components/Controls';
import { CellData, Difficulty, InputMode, DisplayMode } from './types';
import { Trophy, Settings, Loader2, Play, Pause, Lightbulb, Grid3x3, Sparkles, Brain, Flame } from 'lucide-react';

const App: React.FC = () => {
  // --- State ---
  const [board, setBoard] = useState<CellData[][]>(createEmptyBoard());
  const [selectedPos, setSelectedPos] = useState<{ r: number; c: number } | null>(null);
  const [difficulty, setDifficulty] = useState<Difficulty>('Easy');
  const [inputMode, setInputMode] = useState<InputMode>('numpad');
  const [displayMode, setDisplayMode] = useState<DisplayMode>('arabic'); 
  const [status, setStatus] = useState<'idle' | 'loading' | 'playing' | 'paused' | 'won'>('idle');
  const [timer, setTimer] = useState(0);
  const [history, setHistory] = useState<CellData[][][]>([]);
  const [mistakes, setMistakes] = useState(0);
  const [hints, setHints] = useState(3);
  const [showSettings, setShowSettings] = useState(false);
  const [hintMessage, setHintMessage] = useState<string | null>(null);

  // --- Game Logic ---

  const startNewGame = useCallback((diff: Difficulty) => {
    setStatus('loading');
    setDifficulty(diff);
    // Slight delay to allow UI to show loading state
    setTimeout(() => {
      const newBoard = generateSudoku(diff);
      setBoard(newBoard);
      setHistory([]);
      setTimer(0);
      setMistakes(0);
      setHints(3);
      setStatus('playing');
      setHintMessage(null);
    }, 400); // Increased slightly for smoother transition feel
  }, []);

  // Timer
  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (status === 'playing') {
      interval = setInterval(() => {
        setTimer((t) => t + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [status]);

  // Keyboard Support
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (status !== 'playing') return;

      // Navigation
      if (selectedPos) {
        const { r, c } = selectedPos;
        if (e.key === 'ArrowUp') setSelectedPos({ r: Math.max(0, r - 1), c });
        if (e.key === 'ArrowDown') setSelectedPos({ r: Math.min(8, r + 1), c });
        if (e.key === 'ArrowLeft') setSelectedPos({ r, c: Math.max(0, c - 1) });
        if (e.key === 'ArrowRight') setSelectedPos({ r, c: Math.min(8, c + 1) });
      }

      // Input
      if (e.key >= '1' && e.key <= '9') {
        handleNumberInput(parseInt(e.key));
      }
      if (e.key === 'Backspace' || e.key === 'Delete') {
        handleErase();
      }
      if (e.key === 'z' && (e.ctrlKey || e.metaKey)) {
        handleUndo();
      }
      if (e.key === 'n') {
        setInputMode(prev => prev === 'note' ? 'numpad' : 'note');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
