    if (hintMessage) setHintMessage(null);
  };

  const updateBoardWithHistory = (newBoard: CellData[][]) => {
    setHistory((prev) => [...prev, board]); // Push current state
    setBoard(newBoard);
    checkWinCondition(newBoard);
  };

  const handleNumberInput = (num: number, modeOverride?: 'value' | 'note') => {
    if (!selectedPos || status !== 'playing') return;
    const { r, c } = selectedPos;
    const cell = board[r][c];

    if (cell.isFixed) return;

    // Determine effective mode: override takes precedence, otherwise use global state
    const effectiveMode = modeOverride === 'note' || (modeOverride === undefined && inputMode === 'note') ? 'note' : 'value';

    // Create deep copy
    const newBoard = board.map(row => row.map(cell => ({ ...cell, notes: [...cell.notes] })));
    const targetCell = newBoard[r][c];

    if (effectiveMode === 'note') {
      // Toggle Note
      if (targetCell.notes.includes(num)) {
        targetCell.notes = targetCell.notes.filter(n => n !== num);
      } else {
        targetCell.notes.push(num);
        targetCell.notes.sort();
      }
    } else {
      // Set Value
      if (targetCell.value === num) return; // No change

      targetCell.value = num;
      targetCell.notes = []; // Clear notes on set

      // Validation
      if (num !== targetCell.solution) {
        targetCell.isError = true;
        setMistakes(m => m + 1);
      } else {
        targetCell.isError = false;
      }
    }

    updateBoardWithHistory(newBoard);
