// --- Main Recognizer Function ---
export const recognizeDigit = (strokes: Point[][]): number | null => {
  if (strokes.length === 0) return null;

  // 1. Join strokes and get basic bounds
  const rawPoints = strokes.flat();
  if (rawPoints.length < 5) return null;

  // 2. Aspect Ratio Check for '1'
  // '1' is unique because it is usually very narrow. Normalization destroys this info.
  const bounds = getBounds(rawPoints);
  const width = bounds.maxX - bounds.minX;
  const height = bounds.maxY - bounds.minY;

  if (height > 20 && width / height < 0.3) {
     return 1;
  }

  // 3. Pre-processing Pipeline
  let points = resample(rawPoints, RESAMPLE_POINTS_COUNT);
  points = smoothPoints(points); // Reduce jitter
  points = translateToOrigin(points);
  points = normalizeScale(points); // Scale to standard box

  // 4. Matching
  let bestMatch: number | null = null;
  let bestScore = Infinity;

  for (const [digitStr, variations] of Object.entries(TEMPLATES)) {
    const digit = parseInt(digitStr);

    for (const template of variations) {
      // Check standard direction
      const d1 = pathDistance(points, template);

      // Check reverse direction (e.g. drawing 1 from bottom up, or 0 clockwise vs counter)
      const d2 = pathDistance(points, [...template].reverse());

      const score = Math.min(d1, d2);

      if (score < bestScore) {
        bestScore = score;
        bestMatch = digit;
      }
    }
  }

  // Debug logging can be enabled here if needed
  // console.log(`Best match: ${bestMatch} with score: ${bestScore}`);

  return bestScore < MAX_DISTANCE_THRESHOLD ? bestMatch : null;
};

// --- Helpers ---

const getBounds = (points: Point[]) => {
  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    minX = Math.min(minX, p.x);
    maxX = Math.max(maxX, p.x);
    minY = Math.min(minY, p.y);
    maxY = Math.max(maxY, p.y);
  }
  return { minX, maxX, minY, maxY };
};

// Smooth points to remove hand jitter using simple moving average
const smoothPoints = (points: Point[]): Point[] => {
  if (points.length < 3) return points;
  const newPoints = [points[0]];
  for (let i = 1; i < points.length - 1; i++) {
    newPoints.push({
      x: (points[i-1].x + points[i].x + points[i+1].x) / 3,
      y: (points[i-1].y + points[i].y + points[i+1].y) / 3
    });
  }
  newPoints.push(points[points.length - 1]);
  return newPoints;
};

// Translate centroid to (0,0)
const translateToOrigin = (points: Point[]): Point[] => {
  const c = centroid(points);
  return points.map(p => ({ x: p.x - c.x, y: p.y - c.y }));
};

const centroid = (points: Point[]): Point => {
  let x = 0, y = 0;
  for (const p of points) { x += p.x; y += p.y; }
  return { x: x / points.length, y: y / points.length };
};

// Scale to a 1x1 box, maintaining shape distortion (standard for text recognizers)
// unless one dimension is nearly 0
const normalizeScale = (points: Point[]): Point[] => {
  const { minX, maxX, minY, maxY } = getBounds(points);
  const width = Math.max(maxX - minX, 0.01); // Avoid div by zero
  const height = Math.max(maxY - minY, 0.01);

  return points.map(p => ({
    x: (p.x - minX) / width,
    y: (p.y - minY) / height
  }));
};

const pathLength = (points: Point[]): number => {
  let d = 0;
  for (let i = 1; i < points.length; i++) {
    d += distance(points[i - 1], points[i]);
  }
  return d;
};

const distance = (p1: Point, p2: Point) => {
  const dx = p1.x - p2.x;
  const dy = p1.y - p2.y;
  return Math.sqrt(dx * dx + dy * dy);
};

// Resample a path to exactly n points evenly spaced
const resample = (points: Point[], n: number): Point[] => {
  const I = pathLength(points) / (n - 1);
  if (I === 0) return Array(n).fill(points[0]); // Handle single point case

  let D = 0;
  const newPoints: Point[] = [points[0]];
  let i = 1;

  // Clone to avoid modifying original array logic during splice (though we don't splice here)
  const srcPts = [...points];

  while (i < srcPts.length) {
    const d = distance(srcPts[i - 1], srcPts[i]);
    if (D + d >= I) {
      const qx = srcPts[i - 1].x + ((I - D) / d) * (srcPts[i].x - srcPts[i - 1].x);
      const qy = srcPts[i - 1].y + ((I - D) / d) * (srcPts[i].y - srcPts[i - 1].y);
      const q = { x: qx, y: qy };
      newPoints.push(q);
      // We essentially "insert" q to measure distance from it for the next point
      srcPts.splice(i, 0, q); 
      D = 0;
    } else {
      D += d;
    }
    i++;
  }

  // Fill any remaining due to floating point rounding errors
  while (newPoints.length < n) {
    newPoints.push(srcPts[srcPts.length - 1]);
  }

  return newPoints;
};

// Average Euclidean distance between corresponding points
const pathDistance = (path1: Point[], path2: Point[]): number => {
  if (path1.length !== path2.length) return Infinity;
  let d = 0;
  for (let i = 0; i < path1.length; i++) {
    d += distance(path1[i], path2[i]);
  }
  return d / path1.length;
};

