import { CellData, Difficulty } from '../types';

// Constants
const GRID_SIZE = 9;

export const createEmptyBoard = (): CellData[][] => {
  return Array.from({ length: GRID_SIZE }, (_, row) =>
    Array.from({ length: GRID_SIZE }, (_, col) => ({
      row,
      col,
      value: null,
      solution: 0,
      isFixed: false,
      notes: [],
      isError: false,
    }))
  );
};

export const isValid = (board: number[][], row: number, col: number, num: number): boolean => {
  // Row and Col check
  for (let x = 0; x < GRID_SIZE; x++) {
    if (board[row][x] === num && x !== col) return false;
    if (board[x][col] === num && x !== row) return false;
  }

  const startRow = Math.floor(row / 3) * 3;
  const startCol = Math.floor(col / 3) * 3;

  for (let i = 0; i < 3; i++) {
    for (let j = 0; j < 3; j++) {
      const r = startRow + i;
      const c = startCol + j;
      if (board[r][c] === num && (r !== row || c !== col)) return false;
    }
  }

  return true;
};

const solveBoard = (board: number[][]): boolean => {
  for (let row = 0; row < GRID_SIZE; row++) {
    for (let col = 0; col < GRID_SIZE; col++) {
      if (board[row][col] === 0) {
        const nums = [1, 2, 3, 4, 5, 6, 7, 8, 9].sort(() => Math.random() - 0.5);
        for (const num of nums) {
          if (isValid(board, row, col, num)) {
            board[row][col] = num;
            if (solveBoard(board)) return true;
            board[row][col] = 0;
          }
        }
        return false;
      }
    }
  }
  return true;
};

export const generateSudoku = (difficulty: Difficulty): CellData[][] => {
  // 1. Create a solved board
  const rawBoard = Array.from({ length: GRID_SIZE }, () => Array(GRID_SIZE).fill(0));

  // Fill diagonal 3x3 matrices (independent)
  for (let i = 0; i < GRID_SIZE; i += 3) {
    fillBox(rawBoard, i, i);
  }

  // Solve the rest
  solveBoard(rawBoard);

  const solution = rawBoard.map(row => [...row]); // Copy solution

  // 2. Remove digits based on difficulty
  let attempts = difficulty === 'Easy' ? 30 : difficulty === 'Medium' ? 45 : 58;

  while (attempts > 0) {
    let row = Math.floor(Math.random() * GRID_SIZE);
    let col = Math.floor(Math.random() * GRID_SIZE);
    while (rawBoard[row][col] === 0) {
      row = Math.floor(Math.random() * GRID_SIZE);
      col = Math.floor(Math.random() * GRID_SIZE);
    }
    rawBoard[row][col] = 0;
    attempts--;
  }

  // 3. Convert to CellData structure
  return rawBoard.map((row, rIndex) => 
    row.map((val, cIndex) => ({
      row: rIndex,
      col: cIndex,
      value: val === 0 ? null : val,
      solution: solution[rIndex][cIndex],
      isFixed: val !== 0,
      notes: [],
      isError: false,
    }))
  );
};

const fillBox = (board: number[][], rowStart: number, colStart: number) => {
  let num: number;
  for (let i = 0; i < 3; i++) {
    for (let j = 0; j < 3; j++) {
      do {
        num = Math.floor(Math.random() * 9) + 1;
      } while (!isSafeInBox(board, rowStart, colStart, num));
      board[rowStart + i][colStart + j] = num;
    }
  }
};

const isSafeInBox = (board: number[][], rowStart: number, colStart: number, num: number) => {
  for (let i = 0; i < 3; i++) {
    for (let j = 0; j < 3; j++) {
      if (board[rowStart + i][colStart + j] === num) return false;
    }
  }
  return true;
};

import { Point } from "../types";

// --- Configuration ---
const RESAMPLE_POINTS_COUNT = 64; 
const MAX_DISTANCE_THRESHOLD = 0.60; // Slightly stricter to avoid false positives, relying on context to pick the right one

// --- Helpers (Hoisted) ---

function distance(p1: Point, p2: Point) {
  const dx = p1.x - p2.x;
  const dy = p1.y - p2.y;
  return Math.sqrt(dx * dx + dy * dy);
}

function pathLength(points: Point[]): number {
  let d = 0;
  for (let i = 1; i < points.length; i++) {
    d += distance(points[i - 1], points[i]);
  }
  return d;
}

function resample(points: Point[], n: number): Point[] {
  const I = pathLength(points) / (n - 1);
  if (I === 0) return Array(n).fill(points[0]);

  let D = 0;
  const newPoints: Point[] = [points[0]];
  let i = 1;

  const srcPts = [...points];

  while (i < srcPts.length) {
    const d = distance(srcPts[i - 1], srcPts[i]);
    if (D + d >= I) {
      const qx = srcPts[i - 1].x + ((I - D) / d) * (srcPts[i].x - srcPts[i - 1].x);
      const qy = srcPts[i - 1].y + ((I - D) / d) * (srcPts[i].y - srcPts[i - 1].y);
      const q = { x: qx, y: qy };
      newPoints.push(q);
      srcPts.splice(i, 0, q); 
      D = 0;
    } else {
      D += d;
    }
    i++;
  }

  while (newPoints.length < n) {
    newPoints.push(srcPts[srcPts.length - 1]);
  }

  return newPoints;
}

function centroid(points: Point[]): Point {
  let x = 0, y = 0;
  for (const p of points) { x += p.x; y += p.y; }
  return { x: x / points.length, y: y / points.length };
}

function translateToOrigin(points: Point[]): Point[] {
  const c = centroid(points);
  return points.map(p => ({ x: p.x - c.x, y: p.y - c.y }));
}

function getBounds(points: Point[]) {
  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    minX = Math.min(minX, p.x);
    maxX = Math.max(maxX, p.x);
    minY = Math.min(minY, p.y);
    maxY = Math.max(maxY, p.y);
  }
  return { minX, maxX, minY, maxY };
}

function normalizeScale(points: Point[]): Point[] {
  const { minX, maxX, minY, maxY } = getBounds(points);
  const width = Math.max(maxX - minX, 0.01);
  const height = Math.max(maxY - minY, 0.01);

  return points.map(p => ({
    x: (p.x - minX) / width,
    y: (p.y - minY) / height
  }));
}

function smoothPoints(points: Point[]): Point[] {
  if (points.length < 3) return points;
  const newPoints = [points[0]];
  for (let i = 1; i < points.length - 1; i++) {
    newPoints.push({
      x: (points[i-1].x + points[i].x + points[i+1].x) / 3,
      y: (points[i-1].y + points[i].y + points[i+1].y) / 3
    });
  }
  newPoints.push(points[points.length - 1]);
  return newPoints;
}

function pathDistance(path1: Point[], path2: Point[]): number {
  if (path1.length !== path2.length) return Infinity;
  let d = 0;
  for (let i = 0; i < path1.length; i++) {
    d += distance(path1[i], path2[i]);
  }
  return d / path1.length;
}

// --- Scratch-out Detection ---
// Detects if the user is scribbling to erase
function isScratchOut(points: Point[]): boolean {
  const bounds = getBounds(points);
  const width = bounds.maxX - bounds.minX;
  const height = bounds.maxY - bounds.minY;
  const diagonal = Math.sqrt(width * width + height * height);
  const totalLength = pathLength(points);

  // A scratch-out usually has a high ratio of path length to bounding box size
  // and covers a reasonable area
  return totalLength > 2.5 * diagonal && totalLength > 100;
}

