const TEMPLATES: Record<number, Point[][]> = {};
Object.entries(RAW_TEMPLATES).forEach(([digit, variations]) => {
  TEMPLATES[parseInt(digit)] = variations.map(points => {
    const resampled = resample(points, RESAMPLE_POINTS_COUNT);
    const centered = translateToOrigin(resampled);
    return normalizeScale(centered);
  });
});

export interface MatchCandidate {
  digit: number;
  score: number;
}

export const recognizeDigit = (strokes: Point[][]): MatchCandidate[] => {
  if (strokes.length === 0) return [];

  const rawPoints = strokes.flat();
  if (rawPoints.length < 5) return [];

  // 1. Check for erase gesture (Scratch-out)
  // We return a special -1 candidate
  if (isScratchOut(rawPoints)) {
    return [{ digit: -1, score: 0 }]; 
  }

  // 2. Aspect Ratio Check for '1'
  const bounds = getBounds(rawPoints);
  const width = bounds.maxX - bounds.minX;
  const height = bounds.maxY - bounds.minY;

  const isOneLikely = height > 20 && width / height < 0.35;

  // 3. Pre-processing
  let points = resample(rawPoints, RESAMPLE_POINTS_COUNT);
  points = smoothPoints(points);
  points = translateToOrigin(points);
  points = normalizeScale(points);

  // 4. Matching
  const candidates: MatchCandidate[] = [];

  for (const [digitStr, variations] of Object.entries(TEMPLATES)) {
    const digit = parseInt(digitStr);
    let bestDigitScore = Infinity;

    for (const template of variations) {
      const d1 = pathDistance(points, template);
      const d2 = pathDistance(points, [...template].reverse());
      bestDigitScore = Math.min(bestDigitScore, d1, d2);
    }

    // Boost '1' if aspect ratio matches strongly
    if (digit === 1 && isOneLikely) {
        bestDigitScore *= 0.5; 
    }

    candidates.push({ digit, score: bestDigitScore });
  }

  // Sort by score (lower is better)
  candidates.sort((a, b) => a.score - b.score);

  // Filter out very bad matches
  return candidates.filter(c => c.score < MAX_DISTANCE_THRESHOLD);
};

import React, { useRef, useState, useEffect } from 'react';
import { CellData, Point, DisplayMode } from '../types';
import { recognizeDigit, MatchCandidate } from '../services/recognizer';
import AbacusDisplay from './AbacusDisplay';

interface SudokuCellProps {
  cell: CellData;
  isSelected: boolean;
  isActive: boolean;
  isRelated: boolean;
  mode: 'numpad' | 'note'; // We kept type but logic is now hybrid
  displayMode: DisplayMode;
  onClick: () => void;
  onInput: (candidates: MatchCandidate[], mode: 'value' | 'note') => void;
}

const SudokuCell: React.FC<SudokuCellProps> = ({
  cell,
  isSelected,
  isActive,
  isRelated,
  mode,
  displayMode,
  onClick,
  onInput
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const strokes = useRef<Point[][]>([]);
  const currentStroke = useRef<Point[]>([]);
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Interaction state for Tap vs Write detection
  const interactionStartRef = useRef<Point | null>(null);
  const isInteractingRef = useRef(false);
  const hasMovedRef = useRef(false);

  // Clean up timeout
  useEffect(() => {
    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
    };
  }, []);

  const baseClasses = "relative flex items-center justify-center text-xl sm:text-2xl md:text-3xl cursor-pointer select-none transition-all duration-200 border-r border-b border-slate-300 dark:border-slate-700 touch-none"; // Added touch-none to prevent scrolling while writing

  let bgClass = "bg-white dark:bg-slate-800";
  if (cell.isError) bgClass = "bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400";
  else if (isSelected) bgClass = "bg-indigo-500 text-white shadow-lg scale-105 z-10 rounded-md";
  else if (isActive) bgClass = "bg-indigo-200 dark:bg-indigo-900/50 text-indigo-900 dark:text-indigo-100";
  else if (isRelated) bgClass = "bg-slate-100 dark:bg-slate-700/50";

  const textClass = cell.isFixed 
    ? (isSelected ? "font-bold" : "font-bold text-slate-900 dark:text-slate-100") 
    : (isSelected ? "font-medium" : "font-medium text-indigo-600 dark:text-indigo-400");

  // Reset canvas when selection changes
  useEffect(() => {
    if (!canvasRef.current) return;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      ctx.lineWidth = 4; // Thicker for better visibility
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = '#4f46e5'; 
      if (isSelected) ctx.strokeStyle = '#ffffff';
    }
  }, [cell.value, isSelected]);

  const getPos = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    };
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    if (cell.isFixed) return;

    // Capture pointer to track movement outside element if needed (though we usually draw inside)
    (e.target as HTMLElement).setPointerCapture(e.pointerId);

    isInteractingRef.current = true;
    hasMovedRef.current = false;
    interactionStartRef.current = getPos(e);

    // Prepare for potential drawing
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    currentStroke.current = [interactionStartRef.current];
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isInteractingRef.current || !interactionStartRef.current) return;

    const currentPos = getPos(e);

    // Check if moved enough to consider it writing
    if (!hasMovedRef.current) {
        const dist = Math.sqrt(
            Math.pow(currentPos.x - interactionStartRef.current.x, 2) + 
            Math.pow(currentPos.y - interactionStartRef.current.y, 2)
        );

        if (dist > 6) { // Threshold in pixels
            hasMovedRef.current = true;
            setIsDrawing(true);

            // If we weren't selected, select now implicitly
            if (!isSelected) onClick();
        }
    }

    if (hasMovedRef.current) {
        // Draw logic
        currentStroke.current.push(currentPos);
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx) {
            ctx.beginPath();
            // Simple quadratic bezier for smoother lines could be added, but lineTo is fast
            const prev = currentStroke.current[currentStroke.current.length - 2];
            ctx.moveTo(prev.x, prev.y);
            ctx.lineTo(currentPos.x, currentPos.y);
            ctx.stroke();
        }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (!isInteractingRef.current) return;
    isInteractingRef.current = false;
    (e.target as HTMLElement).releasePointerCapture(e.pointerId);

    if (!hasMovedRef.current) {
        // Was a tap
        onClick();
        // Clear any accidental sub-threshold dots
        const ctx = canvasRef.current?.getContext('2d');
        ctx?.clearRect(0, 0, 100, 100);
    } else {
        // Was a write gesture
        setIsDrawing(false);
        strokes.current.push([...currentStroke.current]);

        // Auto-process after a short delay to allow multi-stroke characters (like 4, 5)
        timeoutRef.current = setTimeout(() => {
            processHandwriting();
        }, 500); // 500ms debounce
    }
  };

  const processHandwriting = () => {
    if (strokes.current.length === 0) return;

    const candidates = recognizeDigit(strokes.current);

    if (candidates.length > 0) {
       // Pass all candidates to parent for Contextual Intelligence
       onInput(candidates, 'value'); // Handwriting always maps to Value in this hybrid mode
    }

    // Clear Canvas with fade effect? For now, instant clear.
    if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        ctx?.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
    strokes.current = [];
  };

  return (
    <div 
      className={`${baseClasses} ${bgClass}`}
      style={{ aspectRatio: '1/1' }}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onPointerCancel={handlePointerUp}
    >
      {/* Main Value */}
      {cell.value && (
        displayMode === 'abacus' ? (
          <div className="w-full h-full p-1 sm:p-2 animate-in fade-in zoom-in-90 duration-300 pointer-events-none">
            <AbacusDisplay value={cell.value} />
          </div>
        ) : (
          <span className={`${textClass} text-3xl animate-in fade-in zoom-in-90 duration-200 pointer-events-none`}>{cell.value}</span>
        )
      )}

      {/* Pencil Marks / Notes */}
      {!cell.value && cell.notes.length > 0 && (
        <div className="grid grid-cols-3 gap-0.5 p-0.5 w-full h-full pointer-events-none">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
            <div key={n} className="flex items-center justify-center text-[8px] sm:text-[10px] leading-none text-slate-500 dark:text-slate-400">
              {cell.notes.includes(n) ? n : ''}
            </div>
          ))}
        </div>
      )}

      {/* Canvas Layer - Always Present for Hybrid Input */}
      {!cell.isFixed && (
        <canvas 
            ref={canvasRef}
            width={100} 
            height={100}
            className="absolute inset-0 w-full h-full pointer-events-none" 
            // pointer-events-none is vital here: the DIV handles the events, the canvas just renders.
        />
      )}

      {/* Helper text when empty and selected to hint capability */}
      {isSelected && !cell.value && !isDrawing && (
        <span className="absolute bottom-1 text-[8px] text-indigo-300 dark:text-indigo-400 opacity-50 pointer-events-none">
           Write
        </span>
      )}
    </div>
  );
};

