    // 2. Resolve best candidate
    let bestDigit = candidates[0].digit;

    // Contextual Intelligence:
    // If we have ambiguity (multiple candidates with good scores), 
    // prefer the one that is valid in the current board state.
    if (candidates.length > 1) {
        // Create a simple number matrix for validation
        const numBoard = board.map(row => row.map(cell => cell.value || 0));

        // Find first candidate that is valid
        const validCandidate = candidates.find(cand => isValid(numBoard, r, c, cand.digit));

        if (validCandidate) {
            bestDigit = validCandidate.digit;
        }
    }

    // 3. Apply
    // If inputMode is 'note', we use notes. 
    // If user explicitly toggles 'Note' mode, handwriting adds notes.
    const isNote = inputMode === 'note';
    updateCell(r, c, bestDigit, isNote);

