    if (historyIndex > 0) {
        setHistoryIndex(h => h - 1);
        setBoard(history[historyIndex - 1]);
    }
  };

  const handleErase = () => {
    if (selectedPos) {
        updateCell(selectedPos.r, selectedPos.c, null);
    }
  };

