const App: React.FC = () => {
  // --- State ---
  const [board, setBoard] = useState<CellData[][]>(createEmptyBoard());
  const [selectedPos, setSelectedPos] = useState<{ r: number; c: number } | null>(null);
  const [difficulty, setDifficulty] = useState<Difficulty>('Easy');
  const [inputMode, setInputMode] = useState<InputMode>('numpad'); // 'note' or 'numpad'. 'handwriting' is implicit.
  const [displayMode, setDisplayMode] = useState<DisplayMode>('arabic'); 
  const [status, setStatus] = useState<'idle' | 'loading' | 'playing' | 'paused' | 'won'>('idle');
  const [timer, setTimer] = useState(0);
  const [history, setHistory] = useState<CellData[][][]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [mistakes, setMistakes] = useState(0);
  const [hintsRemaining, setHintsRemaining] = useState(3);
  const [isProcessingHint, setIsProcessingHint] = useState(false);
  const [hintMessage, setHintMessage] = useState<string | null>(null);

  // --- Timer ---
  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (status === 'playing') {
      interval = setInterval(() => setTimer(t => t + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [status]);

  // --- Game Logic ---
  const startNewGame = useCallback((diff: Difficulty = difficulty) => {
    setStatus('loading');
    setDifficulty(diff);
    // Small delay to allow UI to show loading state
    setTimeout(() => {
      const newBoard = generateSudoku(diff);
      setBoard(newBoard);
      setHistory([newBoard]);
      setHistoryIndex(0);
      setTimer(0);
      setMistakes(0);
      setHintsRemaining(3);
      setHintMessage(null);
      setStatus('playing');
      setSelectedPos(null);
    }, 100);
  }, [difficulty]);

  // Initial Game
  useEffect(() => {
    if (status === 'idle') {
        startNewGame('Easy');
    }
  }, []);

  const addToHistory = (newBoard: CellData[][]) => {
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(newBoard);
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  };

  const handleCellClick = useCallback((r: number, c: number) => {
    if (status !== 'playing') return;
    setSelectedPos({ r, c });
    setHintMessage(null);
  }, [status]);

  const updateCell = (r: number, c: number, value: number | null, isNote: boolean = false) => {
    const newBoard = board.map(row => row.map(cell => ({ ...cell })));
    const cell = newBoard[r][c];

    if (cell.isFixed) return;

    if (isNote) {
      if (value === null) {
        cell.notes = [];
      } else {
        if (cell.notes.includes(value)) {
          cell.notes = cell.notes.filter(n => n !== value);
        } else {
          cell.notes = [...cell.notes, value].sort();
        }
      }
    } else {
      // Setting Value
      if (cell.value === value) return; // No change

      cell.value = value;
      cell.notes = []; // Clear notes on value set

      // Check for error immediately
      if (value !== null) {
        // Simple check against solution for "Zenith" experience.
        if (value !== cell.solution) {
            cell.isError = true;
            setMistakes(m => m + 1);
        } else {
            cell.isError = false;
        }
      } else {
        cell.isError = false;
      }
    }

    setBoard(newBoard);
    addToHistory(newBoard);

    // Check Win
    if (!isNote && value !== null) {
        checkWin(newBoard);
    }
  };

