// Pre-process templates once at load time
const TEMPLATES: Record<number, Point[][]> = {};
Object.entries(RAW_TEMPLATES).forEach(([digit, variations]) => {
  TEMPLATES[parseInt(digit)] = variations.map(points => {
    // We normalize templates exactly like input
    const resampled = resample(points, RESAMPLE_POINTS_COUNT);
    const centered = translateToOrigin(resampled);
    return normalizeScale(centered);
  });
});

// --- Main Recognizer Function ---
export const recognizeDigit = (strokes: Point[][]): number | null => {
  if (strokes.length === 0) return null;

  // 1. Join strokes and get basic bounds
  const rawPoints = strokes.flat();
  if (rawPoints.length < 5) return null;

  // 2. Aspect Ratio Check for '1'
  // '1' is unique because it is usually very narrow. Normalization destroys this info.
  const bounds = getBounds(rawPoints);
  const width = bounds.maxX - bounds.minX;
  const height = bounds.maxY - bounds.minY;

  // Relaxed threshold for '1' (was 0.3)
  if (height > 20 && width / height < 0.5) {
     return 1;
  }

  // 3. Pre-processing Pipeline
  let points = resample(rawPoints, RESAMPLE_POINTS_COUNT);
  points = smoothPoints(points); // Reduce jitter
  points = translateToOrigin(points);
  points = normalizeScale(points); // Scale to standard box

  // 4. Matching
  let bestMatch: number | null = null;
  let bestScore = Infinity;

  for (const [digitStr, variations] of Object.entries(TEMPLATES)) {
    const digit = parseInt(digitStr);

    for (const template of variations) {
      // Check standard direction
      const d1 = pathDistance(points, template);

      // Check reverse direction (e.g. drawing 1 from bottom up, or 0 clockwise vs counter)
      const d2 = pathDistance(points, [...template].reverse());

      const score = Math.min(d1, d2);

      if (score < bestScore) {
        bestScore = score;
        bestMatch = digit;
      }
    }
  }

  return bestScore < MAX_DISTANCE_THRESHOLD ? bestMatch : null;
};

