Object.entries(RAW_TEMPLATES).forEach(([digit, variations]) => {
  TEMPLATES[parseInt(digit)] = variations.map(points => {
    const resampled = resample(points, RESAMPLE_POINTS_COUNT);
    const centered = translateToOrigin(resampled);
    return normalizeScale(centered);
  });
});

// --- Heuristic Penalty System ---
function applyHeuristicPenalty(digit: number, points: Point[], score: number): number {
  let penalty = 0;

  // Normalized points are required for analysis
  const normPoints = normalizeScale(points);

  const isClosed = isClosedShape(normPoints);
  const comY = getCenterOfMassY(normPoints);
  const centerDensity = getCenterDensity(normPoints);

  switch (digit) {
    case 0:
      // 0 should be empty in the middle
      if (centerDensity > 0.1) penalty += 0.3; 
      // 0 should be closed
      if (!isClosed) penalty += 0.1;
      break;

    case 1:
      // 1 should not be wide (handled by aspect ratio check, but good to reinforce)
      break;

    case 3:
      // 3 is open on the left, open ends
      if (isClosed) penalty += 0.5;
      break;

    case 4:
      // 4 usually has structure in middle, shouldn't be too top heavy
      break;

    case 6:
      // 6 is bottom heavy
      if (comY < 0.45) penalty += 0.4; // If weight is at top, it's likely a 9 or 0
      break;

    case 8:
      // 8 has high density in the center (crossing point)
      if (centerDensity < 0.1) penalty += 0.4; // If empty middle, it's likely a 0
      // 8 is usually closed-ish or crosses
      break;

    case 9:
      // 9 is top heavy
      if (comY > 0.55) penalty += 0.4; // If weight is at bottom, likely a 6
      break;
  }

  return score + penalty;
}

// --- Main Recognizer Function ---
export const recognizeDigit = (strokes: Point[][]): number | null => {
  if (strokes.length === 0) return null;

  // 1. Join strokes for simple analysis
  const rawPoints = strokes.flat();
  if (rawPoints.length < 5) return null;

  // 2. Aspect Ratio Check for '1'
  // '1' is unique because it is usually very narrow. 
  const bounds = getBounds(rawPoints);
  const width = bounds.maxX - bounds.minX;
  const height = bounds.maxY - bounds.minY;

  if (height > 20 && width / height < 0.4) {
     return 1;
  }

  // 3. Pre-processing Pipeline
  let points = resample(rawPoints, RESAMPLE_POINTS_COUNT);
  points = smoothPoints(points); 
  points = translateToOrigin(points);
  points = normalizeScale(points); // Scale to standard box

  // 4. Scoring with Heuristics
  const scores: { digit: number, score: number }[] = [];

  for (const [digitStr, variations] of Object.entries(TEMPLATES)) {
    const digit = parseInt(digitStr);
    let bestTemplateScore = Infinity;

    for (const template of variations) {
      // Check standard direction
      const d1 = pathDistance(points, template);
      // Check reverse direction
      const d2 = pathDistance(points, [...template].reverse());

      bestTemplateScore = Math.min(bestTemplateScore, Math.min(d1, d2));
    }

    // Apply Logic Penalties
    const finalScore = applyHeuristicPenalty(digit, points, bestTemplateScore);
    scores.push({ digit, score: finalScore });
  }

  // 5. Sort by best score (lowest is best)
  scores.sort((a, b) => a.score - b.score);

  const bestMatch = scores[0];
  const secondBest = scores[1];

  // Debugging log (optional, helpful for dev)
  // console.log("Recognition Scores:", scores.slice(0, 3));

  // 6. Thresholding & Confidence Check
  if (bestMatch.score > MAX_DISTANCE_THRESHOLD) {
    return null; // No good match
  }

  // Confidence check: If top 2 are very close, it's ambiguous. 
  // However, if the best match is essentially perfect (very low score), accept it anyway.
  if (bestMatch.score > 0.15 && (secondBest.score - bestMatch.score < CONFIDENCE_GAP_THRESHOLD)) {
     return null; // Ambiguous result (e.g. messy 4 vs 9)
  }

  return bestMatch.digit;
};

import { Point } from "../types";

// --- Configuration ---
const RESAMPLE_POINTS_COUNT = 64; 
const MAX_DISTANCE_THRESHOLD = 0.55; // Slightly stricter
const CONFIDENCE_GAP_THRESHOLD = 0.05; 

// --- Helpers ---

function distance(p1: Point, p2: Point) {
  const dx = p1.x - p2.x;
  const dy = p1.y - p2.y;
  return Math.sqrt(dx * dx + dy * dy);
}

function pathLength(points: Point[]): number {
  let d = 0;
  for (let i = 1; i < points.length; i++) {
    d += distance(points[i - 1], points[i]);
  }
  return d;
}

function resample(points: Point[], n: number): Point[] {
  const I = pathLength(points) / (n - 1);
  if (I === 0) return Array(n).fill(points[0]); 

  let D = 0;
  const newPoints: Point[] = [points[0]];
  let i = 1;
  const srcPts = [...points];

  while (i < srcPts.length) {
    const d = distance(srcPts[i - 1], srcPts[i]);
    if (D + d >= I) {
      const qx = srcPts[i - 1].x + ((I - D) / d) * (srcPts[i].x - srcPts[i - 1].x);
      const qy = srcPts[i - 1].y + ((I - D) / d) * (srcPts[i].y - srcPts[i - 1].y);
      const q = { x: qx, y: qy };
      newPoints.push(q);
      srcPts.splice(i, 0, q); 
      D = 0;
    } else {
      D += d;
    }
    i++;
  }

  while (newPoints.length < n) {
    newPoints.push(srcPts[srcPts.length - 1]);
  }

  return newPoints;
}

function centroid(points: Point[]): Point {
  let x = 0, y = 0;
  for (const p of points) { x += p.x; y += p.y; }
  return { x: x / points.length, y: y / points.length };
}

function translateToOrigin(points: Point[]): Point[] {
  const c = centroid(points);
  return points.map(p => ({ x: p.x - c.x, y: p.y - c.y }));
}

function getBounds(points: Point[]) {
  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    minX = Math.min(minX, p.x);
    maxX = Math.max(maxX, p.x);
    minY = Math.min(minY, p.y);
    maxY = Math.max(maxY, p.y);
  }
  return { minX, maxX, minY, maxY };
}

function normalizeScale(points: Point[]): Point[] {
  const { minX, maxX, minY, maxY } = getBounds(points);
  const width = Math.max(maxX - minX, 0.01); 
  const height = Math.max(maxY - minY, 0.01);

  return points.map(p => ({
    x: (p.x - minX) / width,
    y: (p.y - minY) / height
  }));
}

function smoothPoints(points: Point[]): Point[] {
  if (points.length < 3) return points;
  const newPoints = [points[0]];
  for (let i = 1; i < points.length - 1; i++) {
    newPoints.push({
      x: (points[i-1].x + points[i].x + points[i+1].x) / 3,
      y: (points[i-1].y + points[i].y + points[i+1].y) / 3
    });
  }
  newPoints.push(points[points.length - 1]);
  return newPoints;
}

function pathDistance(path1: Point[], path2: Point[]): number {
  if (path1.length !== path2.length) return Infinity;
  let d = 0;
  for (let i = 0; i < path1.length; i++) {
    d += distance(path1[i], path2[i]);
  }
  return d / path1.length;
}

// --- Structural Analysis Helpers ---

function isClosedShape(points: Point[]): boolean {
  if (points.length < 2) return false;
  const d = distance(points[0], points[points.length - 1]);
  return d < 0.25; 
}

function getCenterOfMassY(points: Point[]): number {
  const c = centroid(points);
  return c.y; 
}

function getRegionDensity(points: Point[], minX: number, maxX: number, minY: number, maxY: number): number {
  let count = 0;
  for (const p of points) {
    if (p.x >= minX && p.x <= maxX && p.y >= minY && p.y <= maxY) {
      count++;
    }
  }
  return count / points.length;
}

