// --- Advanced Heuristics ---

function applyHeuristicPenalty(digit: number, points: Point[], score: number): number {
  let penalty = 0;
  const normPoints = normalizeScale(points);
  const profile = getHorizontalProfile(normPoints);
  const startPt = normPoints[0];
  const endPt = normPoints[normPoints.length - 1];
  const endpointDist = distance(startPt, endPt);
  const centerOfMass = centroid(normPoints);

  switch (digit) {
    case 1:
        // No heavy checks needed, aspect ratio handles it
        break;

    case 4:
        // 4 usually has a crossbar. Mid density usually high.
        break;

    case 6:
        // 6 is bottom heavy. 
        if (centerOfMass.y < 0.4) penalty += 0.5;
        // Top right should be emptyish
        if (getZoneDensity(normPoints, 0.5, 1, 0, 0.4) > 0.2) penalty += 0.2;
        break;

    case 8:
        // RULE: "Two cavities" / Hourglass shape
        // The middle width should be significantly less than top OR bottom width (waist)
        // OR the middle density must be high (crossing point)
        const hasWaist = (profile.midWidth < profile.topWidth * 0.9) || (profile.midWidth < profile.bottomWidth * 0.9);
        const hasCrossing = getZoneDensity(normPoints, 0.3, 0.7, 0.4, 0.6) > 0.15;

        if (!hasWaist && !hasCrossing) {
            penalty += 0.4; // It's a block, not an 8
        }

        // RULE: Balanced Top/Bottom
        // An 8 usually has ink in all 4 corners roughly
        const bl = getZoneDensity(normPoints, 0, 0.5, 0.5, 1);
        const tr = getZoneDensity(normPoints, 0.5, 1, 0, 0.5);
        if (bl < 0.05 || tr < 0.05) penalty += 0.3;

        break;

    case 9:
        // RULE: "One loop + stem"
        // Top heavy
        if (centerOfMass.y > 0.6) penalty += 0.6; // If mass is low, it's a 6 or 0

        // Stem logic: Bottom Left usually empty (unless curly tail)
        // If bottom left is VERY dense, it's likely an 8 or 6.
        const blDensity = getZoneDensity(normPoints, 0, 0.5, 0.5, 1);
        if (blDensity > 0.25) penalty += 0.5;

        // RULE: Open Bottom
        // Endpoint usually low.
        if (endPt.y < 0.5) penalty += 0.3; 
        break;

    case 0:
        // Center should be empty
        if (getZoneDensity(normPoints, 0.3, 0.7, 0.3, 0.7) > 0.1) penalty += 0.5;
        break;
  }

  return score + penalty;
}

function getZoneDensity(points: Point[], minX: number, maxX: number, minY: number, maxY: number): number {
  let count = 0;
  for (const p of points) {
    if (p.x >= minX && p.x <= maxX && p.y >= minY && p.y <= maxY) {
      count++;
    }
  }
  return count / points.length;
}


// --- Main Function ---
export const recognizeDigit = (strokes: Point[][]): number | null => {
  if (strokes.length === 0) return null;

  const rawPoints = strokes.flat();
  if (rawPoints.length < 5) return null;

  // 1. Aspect Ratio (The '1' detector)
  const bounds = getBounds(rawPoints);
  const width = bounds.maxX - bounds.minX;
  const height = bounds.maxY - bounds.minY;
  if (height > 15 && width / height < 0.30) {
     return 1;
  }

  // 2. Preprocess
  let points = resample(rawPoints, RESAMPLE_POINTS_COUNT);
  points = normalizeScale(translateToOrigin(points));

  // 3. Template Match
  const scores: { digit: number, score: number }[] = [];
  for (const [digitStr, variations] of Object.entries(TEMPLATES)) {
    const digit = parseInt(digitStr);
    let bestScore = Infinity;
    for (const template of variations) {
      const d1 = pathDistance(points, template);
      const d2 = pathDistance(points, [...template].reverse());
      bestScore = Math.min(bestScore, Math.min(d1, d2));
    }
    const finalScore = applyHeuristicPenalty(digit, points, bestScore);
    scores.push({ digit, score: finalScore });
  }

  scores.sort((a, b) => a.score - b.score);
  const best = scores[0];
  const second = scores[1];

  // 4. Tie-Breaker: 8 vs 9 specific logic
  // If the top two are 8 and 9 (in any order), run a specific structural test
  const topTwo = [best.digit, second.digit];
  if (topTwo.includes(8) && topTwo.includes(9) && Math.abs(best.score - second.score) < 0.3) {
      return differentiate8and9(points);
  }

  // 5. General Threshold
  if (best.score > MAX_DISTANCE_THRESHOLD) return null;

  return best.digit;
};

// --- Specialized Discriminators ---

/**
 * The ultimate decision maker for the "8 vs 9" problem based on Topology.
 */
function differentiate8and9(points: Point[]): number {
    const profile = getHorizontalProfile(points);
    const blDensity = getZoneDensity(points, 0, 0.4, 0.6, 1.0);
    const centerDensity = getZoneDensity(points, 0.4, 0.6, 0.4, 0.6);
    const endPt = points[points.length - 1];

    // CRITERIA 1: Bottom Width (Funnel vs Hourglass)
    // 9 usually tapers at bottom (stem). 8 remains wide (bottom loop).
    const isBottomNarrow = profile.bottomWidth < profile.topWidth * 0.7;

    // CRITERIA 2: Bottom Left Presence
    // 8 MUST have presence in bottom left to close the loop.
    // 9 typically does not (unless curly, but then criteria 1 helps).
    const hasBottomLeft = blDensity > 0.1;

    // CRITERIA 3: Endpoint
    // 9 ends at bottom. 8 ends at middle or connects to start.
    const endsAtBottom = endPt.y > 0.8;

    let score8 = 0;
    let score9 = 0;

    // Evaluate 8
    if (hasBottomLeft) score8 += 2; // 8 needs full loops
    if (!isBottomNarrow) score8 += 1; // 8 is wide at bottom
    if (centerDensity > 0.1) score8 += 1; // 8 crosses in middle

    // Evaluate 9
    if (!hasBottomLeft) score9 += 2; // 9 has open stem
    if (isBottomNarrow) score9 += 1; // 9 tapers
    if (endsAtBottom) score9 += 1; // 9 tails off

    return score8 >= score9 ? 8 : 9;
}

