// --- Discriminator: 8 vs 9 ---

/**
 * STRICT Topological Rules for 8 vs 9
 * 8: Two loops, Hourglass, Bottom Closure.
 * 9: One loop (top), Funnel, Open Bottom / Stem.
 */
function isEightOrNine(points: Point[]): { digit: number, confidence: string, explanation: string } {
    const endPt = points[points.length - 1];

    // 1. Zonal Density Analysis
    const topLeft     = getZoneDensity(points, 0, 0.5, 0, 0.5);
    const topRight    = getZoneDensity(points, 0.5, 1, 0, 0.5);
    const bottomLeft  = getZoneDensity(points, 0, 0.5, 0.5, 1);
    const bottomRight = getZoneDensity(points, 0.5, 1, 0.5, 1);
    const center      = getZoneDensity(points, 0.35, 0.65, 0.35, 0.65);

    // 2. Bottom Closure Analysis (Crucial for 8)
    // Check if there is ink spanning across the bottom (left -> right)
    const bottomSpan = points.filter(p => p.y > 0.75);
    let minBottomX = 1, maxBottomX = 0;
    if (bottomSpan.length > 0) {
        bottomSpan.forEach(p => {
            minBottomX = Math.min(minBottomX, p.x);
            maxBottomX = Math.max(maxBottomX, p.x);
        });
    }
    const hasWideBottom = (maxBottomX - minBottomX) > 0.6; // 8 needs a wide base

    // 3. Return Stroke Analysis
    // Does the pen go deep down (Y > 0.8) and then come back UP significantly?
    // An 8 usually returns to the center (Y ~ 0.5). A 9 stays low.
    let minStrokeY = 0;
    let maxStrokeY = 0;
    let hasDeepDip = false;
    let hasReturnUp = false;

    // Scan the second half of the stroke
    const secondHalf = points.slice(Math.floor(points.length / 2));
    for (const p of secondHalf) {
        if (p.y > 0.85) hasDeepDip = true;
    }

    // Check if endpoint is significantly higher than the lowest point (Return stroke)
    // Or if the endpoint meets the start point (Closed loop)
    const lowestY = Math.max(...points.map(p => p.y));
    const distToEnd = distance(points[0], endPt);

    if (hasDeepDip && (lowestY - endPt.y > 0.25 || distToEnd < 0.2)) {
        hasReturnUp = true;
    }

    // --- DECISION TREE ---

    // Rule 1: The "9 Stem" Rule.
    // If the bottom-left quadrant is empty, it CANNOT be an 8.
    // 8 requires the loop to go bottom-right -> bottom-left -> center.
    if (bottomLeft < 0.05) {
        return { digit: 9, confidence: "High", explanation: "Bottom-left empty (Stem detected)" };
    }

    // Rule 2: The "Return Stroke" Rule.
    // If it goes down and comes back up to close a loop, it's an 8.
    if (hasReturnUp && hasWideBottom) {
        return { digit: 8, confidence: "High", explanation: "Return stroke detected (Bottom loop closed)" };
    }

    // Rule 3: The "Endpoint" Rule.
    // If it ends at the very bottom, it's likely a 9 (Tail).
    if (endPt.y > 0.85 && !hasReturnUp) {
         // Exception: Sloppy 8s might end at bottom if drawn as "S"
         // Check density in center. 8 crosses center.
         if (center > 0.15 && bottomLeft > 0.15) {
             return { digit: 8, confidence: "Low", explanation: "Ends low but has center mass (Sloppy 8)" };
         }
         return { digit: 9, confidence: "Medium", explanation: "Ends at bottom (Tail detected)" };
    }

    // Rule 4: Top-Heaviness (Funnel vs Hourglass)
    const topMass = topLeft + topRight;
    const bottomMass = bottomLeft + bottomRight;

    // 9 is Top Heavy (Big head, stick body)
    // 8 is Balanced (Head and Body)
    if (topMass > bottomMass * 1.5) {
        return { digit: 9, confidence: "Medium", explanation: "Top heavy (Funnel shape)" };
    }

    // Fallback: Default to 8 if there is significant mass everywhere
    if (bottomLeft > 0.1 && bottomRight > 0.1 && topMass > 0.3) {
        return { digit: 8, confidence: "Medium", explanation: "Two volumes detected (Balanced mass)" };
    }

    return { digit: 9, confidence: "Low", explanation: "Fallback to 9" };
}

