    let bestScore = Infinity;
    for (const template of variations) {
      const d1 = pathDistance(points, template);
      const d2 = pathDistance(points, [...template].reverse());
      bestScore = Math.min(bestScore, Math.min(d1, d2));
    }

    // Basic heuristic penalties for non-8/9 digits
    let finalScore = bestScore;
    if (digit === 0 && getZoneDensity(points, 0.4, 0.6, 0.4, 0.6) > 0.2) finalScore += 0.5; // 0 shouldn't be filled
    if (digit === 6 && getZoneDensity(points, 0.6, 1, 0, 0.4) > 0.2) finalScore += 0.3; // 6 empty top-right

    scores.push({ digit, score: finalScore });
  }

  scores.sort((a, b) => a.score - b.score);
  const best = scores[0];
  const second = scores[1];

  // 4. CRITICAL: 8 vs 9 Tie-Breaker
  // If the recognizer is confused between 8 and 9 (or thinks it's one of them), 
  // we force the Topological Analysis.
  const candidates = [best.digit, second.digit];
  const isAmbiguous8or9 = candidates.includes(8) || candidates.includes(9);

  // If the score is decent and it involves 8 or 9, run the specialized logic
  if (isAmbiguous8or9 && best.score < MAX_DISTANCE_THRESHOLD) {
      // If the template match is VERY confident about something else (e.g. 0 or 6), trust it.
      // But if 8 or 9 is in top 2, double check.
      if (best.digit === 8 || best.digit === 9 || second.digit === 8 || second.digit === 9) {
          const result = isEightOrNine(points);
          // console.log(`8vs9 Analysis: Classified as ${result.digit} (${result.explanation})`);
          return result.digit;
      }
  }

  // 5. General Threshold
  if (best.score > MAX_DISTANCE_THRESHOLD) return null;

  return best.digit;
};

export type Difficulty = 'Easy' | 'Medium' | 'Hard';

export interface CellData {
  row: number;
  col: number;
  value: number | null;
  solution: number;
  isFixed: boolean; // Was part of the original puzzle
  notes: number[];
  isError: boolean;
}

export interface GameState {
  board: CellData[][];
  difficulty: Difficulty;
  status: 'idle' | 'playing' | 'paused' | 'won' | 'lost';
  timer: number;
  mistakes: number;
  history: CellData[][][]; // Array of board snapshots
  historyIndex: number;
}

export type InputMode = 'numpad' | 'note';

export type DisplayMode = 'arabic' | 'abacus';

export interface Point {
  x: number;
  y: number;
}

