// --- Heuristic Penalty System ---

/**
 * Calculates a penalty score based on strict structural rules for each digit.
 * Higher penalty = less likely to be that digit.
 */
function calculateStructuralPenalty(digit: number, points: Point[], bounds: {w: number, h: number}): number {
  let penalty = 0;

  // Normalized points (0-1)
  const normPoints = normalizeScale(points);

  const startPt = normPoints[0];
  const endPt = normPoints[normPoints.length - 1];
  const centerOfMass = centroid(normPoints);

  // Density Zones
  const topDensity = getZoneDensity(normPoints, 0, 1, 0, 0.3);
  const bottomDensity = getZoneDensity(normPoints, 0, 1, 0.7, 1);
  const leftDensity = getZoneDensity(normPoints, 0, 0.3, 0, 1);
  const rightDensity = getZoneDensity(normPoints, 0.7, 1, 0, 1);
  const centerDensity = getZoneDensity(normPoints, 0.3, 0.7, 0.3, 0.7);
  const middleHorizontalDensity = getZoneDensity(normPoints, 0, 1, 0.4, 0.6);

  switch (digit) {
    case 0:
      // 0 MUST be closed (start meets end) OR close enough vertically
      if (distance(startPt, endPt) > 0.3) penalty += 0.5;
      // 0 Center should be empty
      if (centerDensity > 0.1) penalty += 0.5;
      // 0 should not end in the middle (unlike 6)
      if (endPt.y > 0.4 && endPt.y < 0.6 && endPt.x > 0.3 && endPt.x < 0.7) penalty += 0.8; 
      break;

    case 1:
      // Handled primarily by Aspect Ratio check in main function, but if it gets here:
      // 1 should be relatively straight. Low horizontal variance.
      if (bounds.w / bounds.h > 0.6) penalty += 0.8; // Too wide
      break;

    case 2:
      // 2 usually has a flat base at the bottom
      const bottomLine = normPoints.filter(p => p.y > 0.9);
      if (bottomLine.length < 5) penalty += 0.2; 
      // Top left should be filled (curve start)
      if (getZoneDensity(normPoints, 0, 0.4, 0, 0.3) < 0.05) penalty += 0.3;
      // Bottom Right should be filled (end of base)
      if (getZoneDensity(normPoints, 0.6, 1, 0.8, 1) < 0.05) penalty += 0.3;
      break;

    case 3:
      // 3 Open on the left
      if (getZoneDensity(normPoints, 0, 0.2, 0.3, 0.7) > 0.1) penalty += 0.5;
      // 3 has middle "tongue"
      if (middleHorizontalDensity < 0.1) penalty += 0.3;
      break;

    case 4:
      // 4 often has a cross. Center density high.
      if (centerDensity < 0.1) penalty += 0.2;
      // 4 usually open at top (or pointed). 
      // Diff vs 9: 9 is round top-right. 4 is usually straight down top-right.
      // If top-left is empty (like a 1), penalty
      if (getZoneDensity(normPoints, 0, 0.4, 0, 0.4) < 0.05 && getZoneDensity(normPoints, 0.6, 1, 0, 0.4) > 0.1) penalty += 0.2;
      break;

    case 5:
      // 5 vs 3: 5 has a "Square" top-left or a horizontal bar.
      // Check for sharp corner in top-left quadrant
      const hasSharpTopLeft = hasSharpTurn(normPoints, 0, 0.4, 110);
      // Check for horizontal top bar
      const topBar = getZoneDensity(normPoints, 0.2, 0.9, 0, 0.15);

      if (!hasSharpTopLeft && topBar < 0.1) {
          // If it looks like a smooth curve at top, it's likely a 3
          penalty += 0.4;
      }
      break;

    case 6:
      // 6 Ends in the bottom-middle loop
      if (endPt.y < 0.5) penalty += 0.6; // Ends too high
      if (endPt.x < 0.2 || endPt.x > 0.8) penalty += 0.3; // Ends too far side
      // Top Right should be empty (the stem is on left)
      if (getZoneDensity(normPoints, 0.6, 1, 0, 0.4) > 0.2) penalty += 0.5;
      break;

    case 7:
      // 7 needs a horizontal top bar.
      if (topDensity < 0.15) penalty += 0.6;
      // Bottom left is usually empty (diagonal down)
      if (getZoneDensity(normPoints, 0, 0.4, 0.6, 1) > 0.1) penalty += 0.3;
      // Unlike 1, 7 is wide at top
      if (bounds.w / bounds.h < 0.3) penalty += 0.5;
      break;

    case 8:
      // 8 Must cross in center
      if (centerDensity < 0.15) penalty += 0.5;
      // Must be closed top and bottom
      if (topDensity < 0.1 || bottomDensity < 0.1) penalty += 0.3;
      // 8 has mass on left and right
      if (leftDensity < 0.15 || rightDensity < 0.15) penalty += 0.3;
      break;

    case 9:
      // 9 has loop at top. Top heavy.
      if (centerOfMass.y > 0.6) penalty += 0.4; // Mass too low (like a 6)
      // Bottom Left should be relatively empty (straight tail or curve right)
      if (getZoneDensity(normPoints, 0, 0.4, 0.6, 1) > 0.2) penalty += 0.6; // Looks like an 8
      // End point should be bottom
      if (endPt.y < 0.6) penalty += 0.5;
      break;
  }

  return penalty;
}


// --- Main Recognizer ---

export const recognizeDigit = (strokes: Point[][]): number | null => {
  if (strokes.length === 0) return null;

  const rawPoints = strokes.flat();
  if (rawPoints.length < 5) return null;

  const bounds = getBounds(rawPoints);
  const width = bounds.maxX - bounds.minX;
  const height = bounds.maxY - bounds.minY;
  const aspectRatio = width / height;

  // --- Early Exit: The "1" Detector ---
  // If it's very thin vertical line, it's a 1.
  if (height > 20 && aspectRatio < 0.25) {
     return 1;
  }

  // --- Preprocess ---
  // We keep aspect ratio for 1 check, but for template matching we normalize to square
  let points = resample(rawPoints, RESAMPLE_POINTS_COUNT);
  points = normalizeScale(translateToOrigin(points));

  // --- Template Matching ---
  const scores: { digit: number, score: number }[] = [];

  for (const [digitStr, variations] of Object.entries(TEMPLATES)) {
    const digit = parseInt(digitStr);
    let bestDist = Infinity;

    // Find best matching template variation
    for (const template of variations) {
      const d1 = pathDistance(points, template);
      const d2 = pathDistance(points, [...template].reverse()); // Check reverse stroke direction
      bestDist = Math.min(bestDist, Math.min(d1, d2));
    }

    // Apply Structural Penalties
    // This is the "Special Sauce" that differentiates similar shapes
    const penalty = calculateStructuralPenalty(digit, points, { w: width, h: height });

    scores.push({ digit, score: bestDist + penalty });
  }

  // Sort by lowest score (distance + penalty)
  scores.sort((a, b) => a.score - b.score);

  const best = scores[0];

  // Debug log for tuning
  // console.log("Recognition Scores:", scores.slice(0, 3).map(s => `${s.digit}: ${s.score.toFixed(3)}`));

  if (best.score > MAX_DISTANCE_THRESHOLD) return null;

  return best.digit;
};

import { Point } from "../types";

// --- Configuration ---
const RESAMPLE_POINTS_COUNT = 64; 
const MAX_DISTANCE_THRESHOLD = 0.45; // Very strict: matches must be close to templates
const CONFIDENCE_GAP_THRESHOLD = 0.08; // The best match must beat the runner-up by this much

// --- Geometry Helpers ---

function distance(p1: Point, p2: Point) {
  const dx = p1.x - p2.x;
  const dy = p1.y - p2.y;
  return Math.sqrt(dx * dx + dy * dy);
}

function pathLength(points: Point[]): number {
  let d = 0;
  for (let i = 1; i < points.length; i++) {
    d += distance(points[i - 1], points[i]);
  }
  return d;
}

function resample(points: Point[], n: number): Point[] {
  const I = pathLength(points) / (n - 1);
  if (I === 0) return Array(n).fill(points[0]); 

  let D = 0;
  const newPoints: Point[] = [points[0]];
  let i = 1;
  const srcPts = [...points];

  while (i < srcPts.length) {
    const d = distance(srcPts[i - 1], srcPts[i]);
    if (D + d >= I) {
      const qx = srcPts[i - 1].x + ((I - D) / d) * (srcPts[i].x - srcPts[i - 1].x);
      const qy = srcPts[i - 1].y + ((I - D) / d) * (srcPts[i].y - srcPts[i - 1].y);
      const q = { x: qx, y: qy };
      newPoints.push(q);
      srcPts.splice(i, 0, q); 
      D = 0;
    } else {
      D += d;
    }
    i++;
  }

  while (newPoints.length < n) {
    newPoints.push(srcPts[srcPts.length - 1]);
  }

  return newPoints;
}

function centroid(points: Point[]): Point {
  let x = 0, y = 0;
  for (const p of points) { x += p.x; y += p.y; }
  return { x: x / points.length, y: y / points.length };
}

function translateToOrigin(points: Point[]): Point[] {
  const c = centroid(points);
  return points.map(p => ({ x: p.x - c.x, y: p.y - c.y }));
}

function getBounds(points: Point[]) {
  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    minX = Math.min(minX, p.x);
    maxX = Math.max(maxX, p.x);
    minY = Math.min(minY, p.y);
    maxY = Math.max(maxY, p.y);
  }
  return { minX, maxX, minY, maxY };
}

function normalizeScale(points: Point[]): Point[] {
  const { minX, maxX, minY, maxY } = getBounds(points);
  const width = Math.max(maxX - minX, 0.01); 
  const height = Math.max(maxY - minY, 0.01);

  // Preserve some aspect ratio info by not stretching excessively if it's a line
  return points.map(p => ({
    x: (p.x - minX) / width,
    y: (p.y - minY) / height
  }));
}

function pathDistance(path1: Point[], path2: Point[]): number {
  if (path1.length !== path2.length) return Infinity;
  let d = 0;
  for (let i = 0; i < path1.length; i++) {
    d += distance(path1[i], path2[i]);
  }
  return d / path1.length;
}

// --- Analysis Tools ---

function getZoneDensity(points: Point[], minX: number, maxX: number, minY: number, maxY: number): number {
  let count = 0;
  for (const p of points) {
    if (p.x >= minX && p.x <= maxX && p.y >= minY && p.y <= maxY) {
      count++;
    }
  }
  return count / points.length;
}

function hasSharpTurn(points: Point[], minIndexPct: number, maxIndexPct: number, angleThreshold: number): boolean {
    const start = Math.floor(points.length * minIndexPct);
    const end = Math.floor(points.length * maxIndexPct);

    // Look for a sharp angle in the specified segment
    for(let i = start; i < end - 2; i += 2) { // Step by 2 to reduce noise
        const p1 = points[i];
        const p2 = points[i+1];
        const p3 = points[i+2];

        const v1 = {x: p1.x - p2.x, y: p1.y - p2.y}; // Vector incoming
        const v2 = {x: p3.x - p2.x, y: p3.y - p2.y}; // Vector outgoing

        const dot = v1.x * v2.x + v1.y * v2.y;
        const mag1 = Math.sqrt(v1.x*v1.x + v1.y*v1.y);
        const mag2 = Math.sqrt(v2.x*v2.x + v2.y*v2.y);

        if (mag1 * mag2 === 0) continue;
        const angle = Math.acos(dot / (mag1 * mag2)) * (180/Math.PI);

        if (angle < angleThreshold) return true;
    }
    return false;
}

