    [{x:0.7,y:0}, {x:0.2,y:0.8}, {x:0.5,y:1}, {x:0.9,y:0.8}, {x:0.7,y:0.6}, {x:0.3,y:0.7}], // Straight back line
    [{x:0.5,y:0}, {x:0,y:0.5}, {x:0.2,y:0.9}, {x:0.8,y:0.9}, {x:0.8,y:0.6}, {x:0.2,y:0.6}] // Big Loop
  ],
