const TEMPLATES: Record<number, Point[][]> = {};
Object.entries(RAW_TEMPLATES).forEach(([digit, variations]) => {
  TEMPLATES[parseInt(digit)] = variations.map(points => {
    const resampled = resample(points, RESAMPLE_POINTS_COUNT);
    const centered = translateToOrigin(resampled);
    return normalizeScale(centered);
  });
});

// --- Structural Verification (The "Certainty" Layer) ---

function getStructuralPenalty(digit: number, points: Point[], bounds: {w: number, h: number}): number {
  let penalty = 0;
  const norm = normalizeScale(points);
  const start = norm[0];
  const end = norm[norm.length - 1];

  // Quadrant Densities
  const dTop    = getZoneDensity(norm, 0, 1, 0, 0.5);
  const dBot    = getZoneDensity(norm, 0, 1, 0.5, 1);
  const dLeft   = getZoneDensity(norm, 0, 0.5, 0, 1);
  const dRight  = getZoneDensity(norm, 0.5, 1, 0, 1);
  const dCenter = getZoneDensity(norm, 0.3, 0.7, 0.3, 0.7);

  switch (digit) {
    case 0:
      // Must be closed loop. End must be near start (top).
      // If it ends in the middle, it might be a 6
      if (distance(start, end) > 0.35) penalty += 1.0; 
      // Center must be relatively empty
      if (dCenter > 0.15) penalty += 0.8; 
      break;

    case 1:
      if (bounds.w / bounds.h > 0.5) penalty += 1.0; 
      if (dLeft > 0.8 || dRight > 0.8) penalty += 0.5;
      break;

    case 2:
      if (getZoneDensity(norm, 0, 1, 0.85, 1) < 0.15) penalty += 0.5;
      if (getZoneDensity(norm, 0, 0.5, 0, 0.3) < 0.05) penalty += 0.3;
      break;

    case 3:
      if (getZoneDensity(norm, 0, 0.25, 0.3, 0.7) > 0.05) penalty += 0.8; 
      if (dCenter < 0.1) penalty += 0.4;
      break;

    case 4:
      // 4 is complex. It usually has vertical lines.
      // Often has a crossing in the middle-ish.
      // If start is top-left and end is bottom-right, it could be a 4 or an X.

      // Reduce penalty for 4 to be more permissive due to variations
      if (dCenter < 0.05) penalty += 0.1; 
      break;

    case 5:
      const hasSharpCorner = hasSharpTurn(norm, 0, 0.4, 110);
      if (!hasSharpCorner) penalty += 0.4; 
      break;

    case 6:
      // 6 must end in the bottom half
      if (end.y < 0.5) penalty += 1.0; 
      // 6 should loop in the bottom. 
      // Check if center-bottom is occupied
      if (getZoneDensity(norm, 0.2, 0.8, 0.6, 0.9) < 0.1) penalty += 0.5;

      // Unlike 0, 6 usually starts at Top-Right or Top-Middle and goes left
      if (start.x < 0.2 && start.y > 0.2) penalty += 0.5; // Starts too low-left
      break;

    case 7:
      if (getZoneDensity(norm, 0, 1, 0, 0.15) < 0.1) penalty += 0.7;
      if (getZoneDensity(norm, 0, 0.4, 0.6, 1) > 0.1) penalty += 0.5;
      break;

    case 8:
      // 8 needs a crossing point or a "pinch" in the middle
      // Standard 8 has high density in center
      if (dCenter < 0.15) penalty += 0.8;
      // Must have mass on top and bottom
      if (dTop < 0.2 || dBot < 0.2) penalty += 0.5;
      break;

    case 9:
      // Top MUST be a loop. 
      // Check density in top-left and top-right
      if (getZoneDensity(norm, 0, 0.5, 0, 0.5) < 0.1) penalty += 0.5;
      if (getZoneDensity(norm, 0.5, 1, 0, 0.5) < 0.1) penalty += 0.5;

      // Tail Logic:
      // If it ends in Bottom-Right (standard) -> OK
      // If it ends in Bottom-Left (curly) -> OK
      // BUT, if it curves back UP to the middle/top, it's an 8 or 0.
      if (end.y < 0.6) penalty += 1.0; // Must end at bottom

      // Mass check: 9 is top-heavy usually
      if (dTop < 0.2) penalty += 0.5;
      break;
  }
  return penalty;
}

export const recognizeDigit = (strokes: Point[][]): number | null => {
  if (strokes.length === 0) return null;

  const rawPoints = strokes.flat();
  if (rawPoints.length < 5) return null;

  // --- 1. Aspect Ratio Pre-check (The "1" Filter) ---
  const bounds = getBounds(rawPoints);
  const width = bounds.maxX - bounds.minX;
  const height = bounds.maxY - bounds.minY;
  const ratio = width / height;

  if (height > 20 && ratio < 0.20) return 1; // Strict vertical line

  // --- 2. Normalization ---
  let points = resample(rawPoints, RESAMPLE_POINTS_COUNT);
  points = normalizeScale(translateToOrigin(points));

  // --- 3. Scoring ---
  const candidates: { digit: number, score: number }[] = [];

  for (const [digitStr, variations] of Object.entries(TEMPLATES)) {
    const digit = parseInt(digitStr);
    let minDist = Infinity;

    for (const t of variations) {
      const d1 = pathDistance(points, t);
      const d2 = pathDistance(points, [...t].reverse());
      minDist = Math.min(minDist, Math.min(d1, d2));
    }

    // Apply strict structural penalties
    const penalty = getStructuralPenalty(digit, points, {w: width, h: height});
    candidates.push({ digit, score: minDist + penalty });
  }

  // --- 4. Selection & Certainty Check ---
  candidates.sort((a, b) => a.score - b.score);
  const best = candidates[0];
  const runnerUp = candidates[1];

  // Rule 1: Must meet absolute threshold
  if (best.score > MAX_DISTANCE_THRESHOLD) {
    return null;
  }

  // Rule 2: Confidence Gap (Must be significantly better than 2nd place)
  const gap = runnerUp.score - best.score;
  if (gap < CONFIDENCE_GAP_THRESHOLD) {
    return null;
  }

  return best.digit;
};

import React, { useRef, useState, useEffect } from 'react';
import { CellData, Point, DisplayMode, InputMode } from '../types';
import { recognizeDigit } from '../services/recognizer';
import AbacusDisplay from './AbacusDisplay';

interface SudokuCellProps {
  cell: CellData;
  isSelected: boolean;
  isActive: boolean;
  isRelated: boolean;
  mode: InputMode; // 'numpad' | 'note'
  displayMode: DisplayMode;
  onClick: () => void;
  onInput: (val: number, mode: 'value' | 'note') => void;
}

const SudokuCell: React.FC<SudokuCellProps> = ({
  cell,
  isSelected,
  isActive,
  isRelated,
  mode,
  displayMode,
  onClick,
  onInput
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const strokes = useRef<Point[][]>([]);
  const currentStroke = useRef<Point[]>([]);
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Gesture state refs
  const isInteractionRef = useRef(false);
  const startPosRef = useRef<Point>({ x: 0, y: 0 });
  const hasMovedRef = useRef(false);

  // Clean up timeout on unmount
  useEffect(() => {
    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
    };
  }, []);

  // Styling logic
  const baseClasses = "relative flex items-center justify-center text-xl sm:text-2xl md:text-3xl cursor-pointer select-none transition-all duration-200 border-r border-b border-slate-300 dark:border-slate-700";

  let bgClass = "bg-white dark:bg-slate-800";
  if (cell.isError) bgClass = "bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400";
  else if (isSelected) bgClass = "bg-indigo-500 text-white shadow-lg scale-105 z-10 rounded-md";
  else if (isActive) bgClass = "bg-indigo-200 dark:bg-indigo-900/50 text-indigo-900 dark:text-indigo-100";
  else if (isRelated) bgClass = "bg-slate-100 dark:bg-slate-700/50";

  const textClass = cell.isFixed 
    ? (isSelected ? "font-bold" : "font-bold text-slate-900 dark:text-slate-100") 
    : (isSelected ? "font-medium" : "font-medium text-indigo-600 dark:text-indigo-400");

  // Clear canvas when selection changes or value updates
  useEffect(() => {
    if (!canvasRef.current) return;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      ctx.lineWidth = 3;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = isSelected ? '#ffffff' : '#4f46e5'; 
    }
  }, [cell.value, isSelected]);

  // --- Pointer Event Handlers (Unified Touch/Mouse) ---

  const handlePointerDown = (e: React.PointerEvent) => {
    // Ignore secondary buttons
    if (e.button !== 0) return;

    // Allow dragging fixed cells to select, but not write
    if (cell.isFixed) {
        // Just trigger click immediately for selection feel, no writing
        onClick();
        return;
    }

    const target = e.target as HTMLElement;
    target.setPointerCapture(e.pointerId);

    isInteractionRef.current = true;
    startPosRef.current = { x: e.clientX, y: e.clientY };

    // PEN OPTIMIZATION:
    // If it's a pen, we assume immediate writing intent. 
    // We set hasMovedRef to true immediately to skip the "drag threshold" check.
    const isPen = e.pointerType === 'pen';
    hasMovedRef.current = isPen;

    if (isPen) {
        setIsDrawing(true);
        if (!isSelected) {
            // If pen touches an unselected cell, treat it as a selection implicitly
            // but we don't trigger onClick to avoid re-render interrupting the stroke
        }
    }

    // Prepare stroke
    if (canvasRef.current) {
        const rect = canvasRef.current.getBoundingClientRect();
        currentStroke.current = [{
            x: e.clientX - rect.left, 
            y: e.clientY - rect.top
        }];
    }

    // Cancel any pending recognition if the user starts writing again quickly
    if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
        timeoutRef.current = null;
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isInteractionRef.current || !canvasRef.current) return;

    const x = e.clientX;
    const y = e.clientY;

    // Detection Threshold (Only for touch/mouse, ignored for Pen)
    if (!hasMovedRef.current) {
        const dist = Math.hypot(x - startPosRef.current.x, y - startPosRef.current.y);
        if (dist > 8) { // 8px threshold
            hasMovedRef.current = true;
            setIsDrawing(true);
        }
    }

    if (hasMovedRef.current) {
        const rect = canvasRef.current.getBoundingClientRect();
        const pos = { x: x - rect.left, y: y - rect.top };

        currentStroke.current.push(pos);

        // Render immediately
        const ctx = canvasRef.current.getContext('2d');
        if (ctx && currentStroke.current.length > 1) {
            ctx.beginPath();
            const prev = currentStroke.current[currentStroke.current.length - 2];
            ctx.moveTo(prev.x, prev.y);
            ctx.lineTo(pos.x, pos.y);
            ctx.stroke();
        }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (!isInteractionRef.current) return;

    isInteractionRef.current = false;
    const target = e.target as HTMLElement;
    target.releasePointerCapture(e.pointerId);

    if (!hasMovedRef.current) {
        // Tap detected (Finger/Mouse only)
        onClick();
        // Clear potential single dot
        const ctx = canvasRef.current?.getContext('2d');
        ctx?.clearRect(0, 0, 80, 80);
    } else {
        // Gesture finished
        if (currentStroke.current.length > 2) { // Ignore tiny accidents
             strokes.current.push([...currentStroke.current]);

             // Auto-recognize after delay
             timeoutRef.current = setTimeout(processHandwriting, 600);
        } else {
            setIsDrawing(false);
            const ctx = canvasRef.current?.getContext('2d');
            ctx?.clearRect(0, 0, 80, 80);
        }
    }
  };

  const processHandwriting = () => {
    if (strokes.current.length === 0) return;

    const digit = recognizeDigit(strokes.current);

    if (digit !== null) {
       // If in Note mode, input as note. Otherwise as value.
       onInput(digit, mode === 'note' ? 'note' : 'value');
    }

    // Reset
    if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        ctx?.clearRect(0, 0, 80, 80);
    }
    strokes.current = [];
    setIsDrawing(false);
  };

  return (
    <div 
      className={`${baseClasses} ${bgClass}`}
      style={{ 
          aspectRatio: '1/1',
          touchAction: 'none' // CRITICAL: Disables browser scrolling on the cell to allow drawing
      }}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onPointerLeave={handlePointerUp}
    >
      {/* Main Value */}
      {cell.value && (
        displayMode === 'abacus' ? (
          <div className="w-full h-full p-1 sm:p-2 animate-in fade-in zoom-in-90 duration-300 pointer-events-none">
            <AbacusDisplay value={cell.value} />
          </div>
        ) : (
          <span className={`${textClass} text-3xl animate-in fade-in zoom-in-90 duration-200 pointer-events-none`}>{cell.value}</span>
        )
      )}

      {/* Pencil Marks / Notes */}
      {!cell.value && cell.notes.length > 0 && (
        <div className="grid grid-cols-3 gap-0.5 p-0.5 w-full h-full pointer-events-none">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
            <div key={n} className="flex items-center justify-center text-[8px] sm:text-[10px] leading-none text-slate-500 dark:text-slate-400">
              {cell.notes.includes(n) ? n : ''}
            </div>
          ))}
        </div>
      )}

      {/* Handwriting Layer - Always present now */}
      {!cell.isFixed && (
        <canvas 
            ref={canvasRef}
            width={80} // Internal res
            height={80}
            className="absolute inset-0 w-full h-full pointer-events-none" // Events handled by parent div
        />
      )}
    </div>
  );
};

export default React.memo(SudokuCell);

