    // NEW: "Ball and Stick" - Counter-Clockwise from right side of ball (lollipop)
    [{x:0.9,y:0.4}, {x:0.5,y:0}, {x:0,y:0.4}, {x:0.5,y:0.6}, {x:0.9,y:0.4}, {x:0.9,y:1}],
    // NEW: "Ball and Stick" - From Top of ball
    [{x:0.5,y:0}, {x:0,y:0.4}, {x:0.5,y:0.6}, {x:1,y:0.4}, {x:0.5,y:0}, {x:1,y:0.5}, {x:1,y:1}]
